"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[9703],{57801:(e,a,n)=>{n.r(a),n.d(a,{data:()=>s});const s={key:"v-5b5c3f28",path:"/git-tutorial/basic.html",title:"Git",lang:"zh-CN",frontmatter:{summary:"Git git是一种源码管理系统（source code management，缩写为SCM）。它对当前文件提供版本管理功能，核心思想是对当前文件建立一个对象数据库（object database），将历史版本信息存放在这个数据库中。 git操作流程 安装git; 提交用户名和电子邮件; 1. git init：新建一个git库 2. git status：",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/git-tutorial/basic.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"Git"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"git操作流程",slug:"git操作流程",children:[{level:3,title:"发布一个版本",slug:"发布一个版本",children:[]}]},{level:2,title:"git对象",slug:"git对象",children:[{level:3,title:"配置",slug:"配置",children:[]}]},{level:2,title:"目录结构",slug:"目录结构",children:[{level:3,title:"缓冲区域（index）",slug:"缓冲区域-index",children:[]}]},{level:2,title:"Git commit的全过程",slug:"git-commit的全过程",children:[]},{level:2,title:"父节点",slug:"父节点",children:[]},{level:2,title:"Tag对象",slug:"tag对象",children:[]},{level:2,title:"Reference（指针）",slug:"reference-指针",children:[]},{level:2,title:"团队开发模式",slug:"团队开发模式",children:[]},{level:2,title:"分支管理策略",slug:"分支管理策略",children:[{level:3,title:"github flow",slug:"github-flow",children:[]},{level:3,title:"Ruby on Rails",slug:"ruby-on-rails",children:[]},{level:3,title:"CMake",slug:"cmake",children:[]}]},{level:2,title:"Git远程操作",slug:"git远程操作",children:[]},{level:2,title:"参考链接",slug:"参考链接",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:6.02,words:1806},filePathRelative:"git-tutorial/basic.md"}},59883:(e,a,n)=>{n.r(a),n.d(a,{default:()=>b});var s=n(66252);const i=(0,s.uE)('<h1 id="git" tabindex="-1"><a class="header-anchor" href="#git" aria-hidden="true">#</a> Git</h1><p>git是一种源码管理系统（source code management，缩写为SCM）。它对当前文件提供版本管理功能，核心思想是对当前文件建立一个对象数据库（object database），将历史版本信息存放在这个数据库中。</p><h2 id="git操作流程" tabindex="-1"><a class="header-anchor" href="#git操作流程" aria-hidden="true">#</a> git操作流程</h2><ul><li>安装git</li><li>提交用户名和电子邮件</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">git</span> config --global user.name <span class="token string">&quot;Some One&quot;</span>\n$ <span class="token function">git</span> config --global user.email <span class="token string">&quot;someone@gmail.com&quot;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol><li>git init：新建一个git库</li><li>git status：查看目前状态</li><li>git add &lt;文件名&gt;：添加文件从工作区到暂存区</li><li>git commit -m &quot;提示信息&quot;：从暂存区提交到代码仓库</li><li>git log：查看提交commit的信息</li><li>git remote add origin https://github.com/try-git/try_git.git : 添加远程指针</li><li>git push -u origin master：将本地的master分支推送到远程origin主机，-u参数表示记住对应关系，下次可以直接git push推送。</li><li>git pull origin master：将远程主机origin的代码取回本地，与本地的master分支合并</li><li>git diff HEAD：查看与上一次commit的区别</li></ol><h3 id="发布一个版本" tabindex="-1"><a class="header-anchor" href="#发布一个版本" aria-hidden="true">#</a> 发布一个版本</h3><p>为当前分支打上版本号。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>$ git tag -a [VERSION] -m &quot;released [VERSION]&quot;\n$ git push origin [VERSION]\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="git对象" tabindex="-1"><a class="header-anchor" href="#git对象" aria-hidden="true">#</a> git对象</h2><p>对象数据库包含四类对象。</p><ul><li>Blob：包含二进制数据，它们是文件内容。只要文件内容改变，就会在对象数据库中生成一个blob对象。注意，blob对象只保存文件内容，不含文件名和文件存储位置等信息。如果文件名改变，或者文件储存位置改变，不会生成新的blob对象。</li><li>Tree：blob对象的集合，以及它们的文件名和权限。一个tree对象描述一个时点上的一个目录。</li><li>Commit：描述一个时点上的项目状态，包含一条log信息，一个tree对象和指向父节点（parent commits）的指针。第一个commit对象没有父节点。 <ul><li>紀錄 root tree SHA1</li><li>紀錄 parent commit SHA1</li><li>紀錄作者、時間和 commit message 資訊</li></ul></li><li>tag</li></ul><p>对象数据库依赖SHA哈希函数。当一个对象加入数据库，它会被SHA函数处理，得到的结果就是该对象在数据库中的名字（前两个字节被当作目录名，用来提高效率）。</p><p>git命令基本上是图数据库操作命令，用来删除/操作节点、移动指针等等。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\n$ <span class="token function">git</span> init\n$ <span class="token builtin class-name">echo</span> hello <span class="token operator">&gt;</span> hello.txt\n$ <span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span>\n$ tree .git\n<span class="token comment"># 存在 .git/objects/ce/013625030ba8dba906f756967f9e9ca394464a</span>\n<span class="token comment"># 這是 hello 內容的 SHA1</span>\n$ <span class="token builtin class-name">printf</span> <span class="token string">&quot;blob 6<span class="token entity" title="\\x00">\\x00</span>hello<span class="token entity" title="\\n">\\n</span>&quot;</span> <span class="token operator">|</span> shasum\n$ <span class="token builtin class-name">echo</span> <span class="token string">&quot;hello&quot;</span> <span class="token operator">|</span> <span class="token function">git</span> hash-object --stdin\n$ <span class="token function">git</span> cat-file -p ce0136\n\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>上面代码有几点需要注意。</p><ul><li><code>git add</code>命令就会生成二进制对象。</li><li>shasum命令返回字符串的SHA哈希函数结果。</li><li><code>git hash-object</code>命令计算一个文件的git对象ID，stdin参数表示从标准输入读取，而不是从本地文件读取。</li><li><code>git cat-file</code>命令显示git对象文件的内容和大小信息，p参数表示以易于阅读的格式显示。</li></ul><p>树对象保存当前目录的快照。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>040000 tree 0eed1217a2947f4930583229987d90fe5e8e0b74 data\n100664 blob 5e40c0877058c504203932e5136051cf3cd3519b letter.txt\n100664 blob 274c0052dd5408f8ae2bc8440029ff67d79bc5c3 number.txt\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>commit（快照）对象也保存在<code>.git/objects</code>目录。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>tree ffe298c3ce8bb07326f888907996eaa48d266db4\nauthor Mary Rose Cook &lt;mary@maryrosecook.com&gt; 1424798436 -0500\ncommitter Mary Rose Cook &lt;mary@maryrosecook.com&gt; 1424798436 -0500\n\na1\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h3><p>指定全局的.gitignore文件。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">git</span> config --global core.excludesfile<span class="token operator">=</span>/Users/flores/.gitignore\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="目录结构" tabindex="-1"><a class="header-anchor" href="#目录结构" aria-hidden="true">#</a> 目录结构</h2><ul><li>.git/refs/heads：保存各个分支的指针</li><li>.git/HEAD 文件，保存HEAD指针</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>ref: refs/heads/master\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>上面代码说明HEAD指向<code>.git/refs/heads/master</code>文件，该文件是一个Hash值。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>a87cc0f39d12e51be8d68eab5cef1d31e8807a1c\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>.git/refs/tags：保存tag指针</li></ul><h3 id="缓冲区域-index" tabindex="-1"><a class="header-anchor" href="#缓冲区域-index" aria-hidden="true">#</a> 缓冲区域（index）</h3><p>Index区域（.git/index）是一个二进制文件，用来保存当前目录在某个时点的状态。</p><p><code>git init</code>命令用来创建index区域，以及对象数据库（.dircache/objects）。</p><p>100644 為檔案模式,表示這是一個普通檔案；100755 表示可執行檔,120000 表示 symbolic link。</p><p><code>.git/index</code>文件，保存暂存区的文件名和对应的Hash值，每行对应一个文件。下面是一个例子。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>data/letter.txt 5e40c0877058c504203932e5136051cf3cd3519b\ndata/number.txt 274c0052dd5408f8ae2bc8440029ff67d79bc5c3\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="git-commit的全过程" tabindex="-1"><a class="header-anchor" href="#git-commit的全过程" aria-hidden="true">#</a> Git commit的全过程</h2><ol><li>用內容產生 blob object</li><li>寫入 file mode, blob SHA1, file name 到 staging area</li><li>根據 staging area 產生 Tree object</li><li>用 root tree SHA1 和 parent commit SHA1 產生 commit object</li><li>用 commit SHA1 更新 master 參考</li></ol><p>如何不用 <code>git add</code> 和 <code>git commit</code>指令完成 commit 動作?</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\n<span class="token comment"># git add的部分</span>\n\n$ <span class="token builtin class-name">echo</span> <span class="token string">&quot;hola&quot;</span> <span class="token operator">|</span> <span class="token function">git</span> hash-object -w --stdin\n$ <span class="token function">git</span> update-index --add --cacheinfo <span class="token punctuation">\\</span>\n<span class="token number">100644</span> 5c1b14949828006ed75a3e8858957f86a2f7e2eb hola.txt\n\n<span class="token comment"># git commit的部分</span>\n\n$ <span class="token function">git</span> write-tree\n$ <span class="token function">git</span> commit-tree 27b9d5 -m <span class="token string">&quot;Second commit&quot;</span> -p 30b060\n$ <span class="token function">git</span> update-ref refs/heads/master 97b806c9e5561a08e0df1f1a60857baad3a1f02e\n\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="父节点" tabindex="-1"><a class="header-anchor" href="#父节点" aria-hidden="true">#</a> 父节点</h2><p>合并产生的新节点，会有两个父节点。第一个是当前所在分支的父节点，第二个合并进来的那个分支的父节点。</p><h2 id="tag对象" tabindex="-1"><a class="header-anchor" href="#tag对象" aria-hidden="true">#</a> Tag对象</h2><p>Tag 分兩種:annotated tag 才會產生 object。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>\n$ <span class="token function">git</span> tag -a release\n$ <span class="token function">git</span> rev-parse release\n$ <span class="token function">git</span> cat-file -p 2450f3\n\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>tag对象的内容。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nobject 309be0\ntype commit\ntag release\ntagger ihower 1375383070 +0800\nRelease!\n\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="reference-指针" tabindex="-1"><a class="header-anchor" href="#reference-指针" aria-hidden="true">#</a> Reference（指针）</h2><p>所谓指针（reference），只是一个链接，用来指向其他物体，方便引用。Git有三种指针，但是所有指针归根结底都是指向某个commit。</p><ul><li>Tag指针：指向某个commit，或者指向某个tag对象。保存位置在.git/refs/tags/目录，文件名为tag名，内容为某个commit或ref object的SHA1哈希。</li><li>Branch指针：指向某个commit。每次该分支有新的commit，指针就会变动。</li><li>HEAD指针：指向目前所在的Branch，用来区分目前在哪个分支。比如，内容为ref: refs/heads/ master。</li></ul><h2 id="团队开发模式" tabindex="-1"><a class="header-anchor" href="#团队开发模式" aria-hidden="true">#</a> 团队开发模式</h2><p>集中式工作流程：團隊內部私有專案，大家都有權限 Push 到共用的 Repository</p><p>管理員工作流程：適合一般 Open Source 專案,只有少部分人有權限可以 Push到 Repository,其他開發者用用 request pull 請求合併。例如 GitHub 提供的 Fork 和 Pull Request 功能。</p><h2 id="分支管理策略" tabindex="-1"><a class="header-anchor" href="#分支管理策略" aria-hidden="true">#</a> 分支管理策略</h2><h3 id="github-flow" tabindex="-1"><a class="header-anchor" href="#github-flow" aria-hidden="true">#</a> github flow</h3><ul><li>master 是 stable/production 可佈署的版本</li><li>任何開發從 master branch 分支出 feature branch</li><li>送 pull request 開始進行行討論、code review和測試</li><li>最後合併回 master 代表可以佈署了</li></ul><p>pros and cons</p><ul><li>簡單、清楚、容易了解</li><li>搭配 Github 的 Pull Request 介面</li><li>沒有 release branch,東⻄一進 master 就上 production</li></ul><h3 id="ruby-on-rails" tabindex="-1"><a class="header-anchor" href="#ruby-on-rails" aria-hidden="true">#</a> Ruby on Rails</h3><ul><li>master 是開發版本</li><li>feature branches 審核完後,合併進 master</li><li>maintenance branches,用 cherry-pick 做 backporting</li><li>基本上就是 Github flow 加上 maintenance branches 維護舊版的設計</li><li>版本號(Tag)打在 master 上,透過 preview 和 beta 的版本號提前釋出</li></ul><h3 id="cmake" tabindex="-1"><a class="header-anchor" href="#cmake" aria-hidden="true">#</a> CMake</h3><ul><li>master 預備釋出的版本,feature branches 從這裡分支出去</li><li>feature branch 完成後,合併進 next</li><li>next 整合版本,完成的 feature branch 先合併到這裡進行測試</li><li>在 next 測好的 feature branch,才合併進 master</li><li>可以將 master 合併進 next,減少之後的 code conflicts</li><li>不會將 next 合併進 master</li><li>nightly 每天 1:00 UTC 自動從 next branch 分支支出來跑自動測試</li></ul><h2 id="git远程操作" tabindex="-1"><a class="header-anchor" href="#git远程操作" aria-hidden="true">#</a> Git远程操作</h2><p>Git的repo一般是用来指本地库，远程库（remote）主要用来存档、合作、分享和触发持续集成。</p><h2 id="参考链接" tabindex="-1"><a class="header-anchor" href="#参考链接" aria-hidden="true">#</a> 参考链接</h2>',65),t=(0,s.Uk)("corbet, "),l={href:"https://lwn.net/Articles/131657/",target:"_blank",rel:"noopener noreferrer"},r=(0,s.Uk)("The guts of git"),c=(0,s.Uk)(": 最早的一篇介绍Git的文章，可以了解Git的总体设计思路"),o=(0,s.Uk)("张文钿, "),d={href:"http://ihower.tw/blog/archives/7938",target:"_blank",rel:"noopener noreferrer"},p=(0,s.Uk)("git从微观到宏观"),u={},b=(0,n(83744).Z)(u,[["render",function(e,a){const n=(0,s.up)("ExternalLinkIcon");return(0,s.wg)(),(0,s.iD)(s.HY,null,[i,(0,s._)("ul",null,[(0,s._)("li",null,[t,(0,s._)("a",l,[r,(0,s.Wm)(n)]),c]),(0,s._)("li",null,[o,(0,s._)("a",d,[p,(0,s.Wm)(n)])])])],64)}]])},83744:(e,a)=>{a.Z=(e,a)=>{const n=e.__vccOpts||e;for(const[e,s]of a)n[e]=s;return n}}}]);